package ai.singlr.sing.gen;

import ai.singlr.sing.config.SingYaml;
import java.util.ArrayList;
import java.util.List;
import java.util.Set;

/**
 * Generates agent-specific hooks configuration that triggers post-task audit scripts. When multiple
 * audits are enabled (security audit + code review), generates an orchestrator script that runs
 * them in parallel and a hooks config pointing to the orchestrator.
 *
 * <p>Pure utility — no I/O, no shell execution. Callers push the generated files into the
 * container.
 */
public final class PostTaskHooksGenerator {

  private PostTaskHooksGenerator() {}

  /**
   * Generates hooks configuration and optional orchestrator script for post-task audits. Collects
   * all enabled audit script paths and produces the appropriate hooks config for the primary agent.
   *
   * @param config the project configuration
   * @param excludeAgents agents to skip during code review auto-resolution
   */
  public static List<GeneratedFile> generateFiles(SingYaml config, Set<String> excludeAgents) {
    if (config.agent() == null) {
      return List.of();
    }

    var sshUser = config.sshUser();
    var scriptPaths = collectAuditScriptPaths(config, sshUser, excludeAgents);

    if (scriptPaths.isEmpty()) {
      return List.of();
    }

    var primaryAgentType = config.agent().type();
    var files = new ArrayList<GeneratedFile>();

    String stopScriptPath;
    if (scriptPaths.size() == 1) {
      stopScriptPath = scriptPaths.getFirst();
    } else {
      var orchestratorPath = "/home/" + sshUser + "/.sing/post-task.sh";
      files.add(new GeneratedFile(orchestratorPath, generateOrchestratorScript(scriptPaths), true));
      stopScriptPath = orchestratorPath;
    }

    var hooksContent = generateHooksConfig(primaryAgentType, stopScriptPath);
    if (hooksContent != null) {
      var hooksPath = hooksConfigPath(primaryAgentType, sshUser);
      files.add(new GeneratedFile(hooksPath, hooksContent, false));
    }

    return files.isEmpty() ? List.of() : List.copyOf(files);
  }

  static List<String> collectAuditScriptPaths(
      SingYaml config, String sshUser, Set<String> excludeAgents) {
    var paths = new ArrayList<String>();

    if (config.agent().securityAudit() != null && config.agent().securityAudit().enabled()) {
      var auditorName =
          config
              .agent()
              .securityAudit()
              .resolveAuditor(config.agent().type(), config.agent().install());
      if (auditorName != null) {
        paths.add("/home/" + sshUser + "/.sing/security-audit.sh");
      }
    }

    if (config.agent().codeReview() != null && config.agent().codeReview().enabled()) {
      var reviewerName =
          config
              .agent()
              .codeReview()
              .resolveAuditor(config.agent().type(), config.agent().install(), excludeAgents);
      if (reviewerName != null) {
        paths.add("/home/" + sshUser + "/.sing/code-review.sh");
      }
    }

    return paths;
  }

  /**
   * Generates an orchestrator script that runs multiple audit scripts in parallel. Exits with code
   * 2 if any audit fails.
   */
  static String generateOrchestratorScript(List<String> scriptPaths) {
    var sb = new StringBuilder();
    sb.append(
        """
        #!/usr/bin/env bash
        set -uo pipefail

        # Post-task orchestrator — runs all audit scripts in parallel.
        # Generated by `sail project create`. Do not edit.

        PIDS=()
        """);

    for (var path : scriptPaths) {
      sb.append(path).append(" &\nPIDS+=($!)\n");
    }

    sb.append(
        """

        FAILED=0
        for pid in "${PIDS[@]}"; do
          wait "$pid" || FAILED=1
        done
        exit $((FAILED > 0 ? 2 : 0))
        """);

    return sb.toString();
  }

  /** Generates hooks configuration for the primary agent type pointing to the stop script. */
  static String generateHooksConfig(String primaryAgentType, String stopScriptPath) {
    return switch (primaryAgentType) {
      case "claude-code" -> generateClaudeCodeHooksConfig(stopScriptPath);
      case "codex" -> generateCodexHooksConfig(stopScriptPath);
      case "gemini" -> generateGeminiHooksConfig(stopScriptPath);
      default -> null;
    };
  }

  /** Returns the hooks config file path inside the container for the given primary agent type. */
  static String hooksConfigPath(String primaryAgentType, String sshUser) {
    return switch (primaryAgentType) {
      case "claude-code" -> "/home/" + sshUser + "/workspace/.claude/settings.json";
      case "codex" -> "/home/" + sshUser + "/workspace/codex.toml";
      case "gemini" -> "/home/" + sshUser + "/workspace/.gemini/settings.json";
      default -> null;
    };
  }

  static String generateClaudeCodeHooksConfig(String scriptPath) {
    return """
        {
          "hooks": {
            "Stop": [
              {
                "matcher": "",
                "hooks": [
                  {
                    "type": "command",
                    "command": "%s"
                  }
                ]
              }
            ]
          }
        }
        """
        .formatted(scriptPath);
  }

  static String generateCodexHooksConfig(String scriptPath) {
    return """
        [[hooks]]
        event = "session_stop"
        command = "%s"
        """
        .formatted(scriptPath);
  }

  static String generateGeminiHooksConfig(String scriptPath) {
    return """
        {
          "hooks": {
            "SessionEnd": [
              {
                "matcher": "*",
                "hooks": [
                  {
                    "name": "post-task-audit",
                    "type": "command",
                    "command": "%s"
                  }
                ]
              }
            ]
          }
        }
        """
        .formatted(scriptPath);
  }
}
